def memoize(f):
    cache = {}
    def wrapper(n):
        if n not in cache:
            cache[n] = f(n)
        return cache[n]
    return wrapper
square = memoize(lambda n: n * n)
print(square(5))
print(square(5))
print(square(7))

def chunks(lst, n):
    result = []
    for i in range(0, len(lst), n):
